/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double>& A,
                      std::vector<double>& B) {
    // Pre‑allocate raw pointers for faster access
    double* a = A.data();
    double* b = B.data();
    const double alpha = 0.33333;

    // Initial loop setup – all indexes are < n
    for (int t = 0; t < tsteps; ++t) {
        /* 1st half‑step: B[i] = α * (A[i‑1] + A[i] + A[i+1]) */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            b[i] = alpha * (a[i - 1] + a[i] + a[i + 1]);
        }

        /* 2nd half‑step: A[i] = α * (B[i‑1] + B[i] + B[i+1]) */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            a[i] = alpha * (b[i - 1] + b[i] + b[i + 1]);
        }
    }
}
