void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A) {

    const int block = 64;                     // inner cache‑friendly block size

    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // --- pre‑scale C[i][0..i] by beta -------------------------------
        double* const ci  = C[i].data();          // start of row i in C
        for (int j = 0; j <= i; ++j) ci[j] *= beta;

        // --- compute rank‑m update ------------------------------------
        const int imax = std::min(i, n-1);         // upper‑triangular
        for (int kk = 0; kk < m; kk += block) {   // block over k
            const int klim = std::min(m, kk+block);
            for (int k = kk; k < klim; ++k) {
                const double aik = A[i][k] * alpha;
                double* const cj = C.data()[0];  // base pointer for C rows
                for (int j = 0; j <= i; ++j) {
                    ci[j] += aik * A[j][k];
                }
            }
        }
    }
}
