/* Main computational kernel.  The whole function will be timed,
   including the call and return. */
void kernel_durbin(int n, std::vector<double>& r, std::vector<double>& y)
{
    // Use raw pointers for speed
    const double* Rp = r.data();
    double*       Yp = y.data();

    // Temporary working space: only the first n elements are used
    std::vector<double> z_vec(n, 0.0);
    double* Zp = z_vec.data();

    // First element
    Yp[0] = -Rp[0];
    double beta  = 1.0;
    double alpha = -Rp[0];

    for (int k = 1; k < n; ++k) {
        beta = (1.0 - alpha * alpha) * beta;

        // Compute the sum r[k-1-i] * y[i] for i = 0..k-1
        double sum = 0.0;
        for (int i = 0; i < k; ++i) {
            sum += Rp[k - i - 1] * Yp[i];
        }

        alpha = -(Rp[k] + sum) / beta;

        // Update temporary vector z
        for (int i = 0; i < k; ++i) {
            Zp[i] = Yp[i] + alpha * Yp[k - i - 1];
        }

        // Copy back to y
        std::memcpy(Yp, Zp, k * sizeof(double));

        Yp[k] = alpha;
    }
}
