void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b) {
    // Pointer cache for each row of L to avoid repeated .data() lookups
    std::vector<double*> l_rows(n);
    for (int i = 0; i < n; ++i) l_rows[i] = L[i].data();

    // Forward substitution
    for (int i = 0; i < n; ++i) {
        double xi = b[i];
        double* lrow = l_rows[i];
        // Unroll inner loop by 4
        int j = 0;
        int end = i & ~3;          // largest multiple of 4 <= i
        for (; j < end; j += 4) {
            xi -= lrow[j]   * x[j];
            xi -= lrow[j+1] * x[j+1];
            xi -= lrow[j+2] * x[j+2];
            xi -= lrow[j+3] * x[j+3];
        }
        for (; j < i; ++j) {       // remaining elements
            xi -= lrow[j] * x[j];
        }
        x[i] = xi / lrow[i];
    }
}
