/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    /* Reinterpret the 2‑D std::vector as a contiguous block to
       reduce indexing overhead and improve cache locality. */
    const std::size_t Astride = static_cast<std::size_t>(m);
    const std::size_t Bstride = static_cast<std::size_t>(n);

    /* Flattened access helpers */
    auto A_flat = reinterpret_cast<const double(*)[Astride]>(A.data());
    auto B_flat = reinterpret_cast<double(*)[Bstride]>(B.data());

    /* Parallelise the outermost loop. Each cache‑line sized block of
       rows is independent because the update accesses only later
       rows (k > i). */
    #pragma omp parallel for schedule(static, 32)
    for (int i = 0; i < m; ++i) {
        double *B_row = B_flat[i];
        for (int j = 0; j < n; ++j) {
            double sum = B_row[j];
            for (int k = i + 1; k < m; ++k) {
                sum += A_flat[k][i] * B_flat[k][j];
            }
            B_row[j] = alpha * sum;
        }
    }
}
```
