/*
 * Optimised ATAX kernel.
 *
 * The algorithm is unchanged:
 *     y = Aᵀ * (A * x)
 * The code is reorganised to use cache‑friendly access patterns and
 * split the serial work into independent parallel chunks.
 */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp)
{
    /* Initialise y to zero – parallelised to avoid a serial loop. */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < n; ++j) y[j] = 0.0;

    /* Parallel over the rows of A.  Each iteration works on one
     * element of tmp and updates the corresponding columns of y.
     * The local reference Arow points to the underlying array of
     * the i‑th std::vector<double>, so we read A sequentially
     * which improves cache behaviour. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        const double* Arow = A[i].data();    // pointer to row i
        double sum = 0.0;

        /* Compute tmp[i] = A[i] · x */
        for (int j = 0; j < n; ++j) sum += Arow[j] * x[j];
        tmp[i] = sum;

        /* Accumulate Aᵀ * tmp[i] into y */
        for (int j = 0; j < n; ++j) y[j] += Arow[j] * sum;
    }
}
