#include <vector>
#include <algorithm>
#include <omp.h>

/* Optimised bicg kernel.  The logic is identical to the
   reference implementation, but the loops are reordered to
   maximise cache reuse and parallelisation.  The outer loop over
   i (the rows of A) is parallelised with OpenMP and the inner
   loop over j (the columns) is kept sequential to keep the write
   locations of s[j] contiguous.  The operation q[i] = Σ (A[i][j] + p[j])
   is split into the sum over A[i][j] and the sum over p[j] so that
   the latter is computed once per i instead of for every j.  This
   preserves numerical consistency while improving performance.  */

void kernel_bicg(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& s,
                 std::vector<double>& q,
                 std::vector<double>& p,
                 std::vector<double>& r)
{
    // Initialise output vectors
    std::fill(s.begin(), s.end(), 0.0);
    std::fill(q.begin(), q.end(), 0.0);

    // Parallel over rows of A
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sumA = 0.0;          // Σ_j A[i][j]
        double sump = 0.0;          // Σ_j p[j]

        const std::vector<double>& Ai = A[i];

        // Inner product r[i] * A[i][j] accumulates into s[j]
        double ri = r[i];
        for (int j = 0; j < m; ++j) {
            s[j] += ri * Ai[j];
        }

        // Compute Σ_j A[i][j] and Σ_j p[j] once per row
        for (int j = 0; j < m; ++j) {
            sumA += Ai[j];
            sump += p[j];
        }
        q[i] = sumA + sump;
    }
}
