void kernel_cholesky(int n, std::vector<std::vector<double>>& A) {
    for (int i = 0; i < n; ++i) {
        // Compute off-diagonal elements
        for (int j = 0; j < i; ++j) {
            double sum = 0.0;
            const std::vector<double>& Ai = A[i];
            const std::vector<double>& Aj = A[j];
            for (int k = 0; k < j; ++k) {
                sum += Ai[k] * Aj[k];
            }
            A[i][j] = (Ai[j] - sum) / Aj[j];
        }

        // Compute diagonal element
        double diag = 0.0;
        const std::vector<double>& Ai = A[i];
        for (int k = 0; k < i; ++k) {
            diag += Ai[k] * Ai[k];
        }
        A[i][i] = std::sqrt(Ai[i] - diag);
    }
}
