```cpp
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_2mm(int ni, int nj, int nk, int nl,
                double alpha,
                double beta,
                std::vector<std::vector<double>>& tmp,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D)
{
    /* We access the underlying row‑major data via raw pointers for
       maximal performance.  We also parallelise the outermost loop
       with OpenMP; all inner loops are kept serial (vectorised by
       the compiler). */
    #pragma omp parallel for
    for (int i = 0; i < ni; ++i) {
        double *tmp_i  = tmp[i].data();
        double *A_i    = A[i].data();
        double *D_i    = D[i].data();

        // -------------------- 1st stage: tmp = alpha * A * B --------------------
        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            const double *Aj = A_i;
            const double *Bj = &B[0][j];            // column `j` of B
            for (int k = 0; k < nk; ++k) {
                sum += alpha * (*Aj) * (*Bj);
                ++Aj;
                Bj += nj;                            // skip to next row in B
            }
            tmp_i[j] = sum;
        }

        // -------------------- 2nd stage: D = beta*D + tmp*C --------------------
        for (int j = 0; j < nl; ++j) {
            double sum = beta * D_i[j];
            const double *tmp_j = tmp_i;
            const double *Cj = &C[0][j];           // column `j` of C
            for (int k = 0; k < nj; ++k) {
                sum += (*tmp_j) * (*Cj);
                ++tmp_j;
                Cj += nj;                          // skip to next row in C
            }
            D_i[j] = sum;
        }
    }
}
