```cpp
#include <vector>
#include <algorithm>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/*
  Original version by Dave Wonnacott at Haverford College <davew@cs.haverford.edu>,
  with help from Allison Lake, Ting Zhou, and Tian Jin,
  based on algorithm by Nussinov, described in Allison Lake's senior thesis.
*/

inline int match(int b1, int b2) { return (b1 + b2 == 3) ? 1 : 0; }

/*  The table is supplied as a vector of vectors.  For speed we
    reinterpret it as a single contiguous block of n*n ints.  The
    caller is responsible for allocating it with n rows of n
    elements each. */
void kernel_nussinov(int n,
                     const std::vector<int> &seq,
                     std::vector<std::vector<int>> &table)
{
    const int *restrict SEQ = seq.data();
    int *restrict TAB = &table[0][0];          // linearised table

    /* Work over the table diagonally so that all data needed for
       a cell is already computed.  Parallelise over the outermost
       diagonal index to share work among 8 threads. */
    #pragma omp parallel for schedule(static)
    for (int d = 1; d < n; ++d) {
        for (int i = 0; i + d < n; ++i) {
            int j = i + d;
            int best = 0;

            /* Two neighbouring cells on the same diag */
            best = std::max(best, TAB[i*n + j - 1]);     // table[i][j-1]
            best = std::max(best, TAB[(i + 1)*n + j]);   // table[i+1][j]

            /* Pair (i,j) */
            if (j - 1 >= i + 1) {                     // j > i+1
                best = std::max(best,
                    TAB[(i + 1)*n + j - 1] + match(SEQ[i], SEQ[j]));
            } else {
                best = std::max(best, TAB[(i + 1)*n + j - 1]);
            }

            /* Split into two sub‑intervals */
            for (int k = i + 1; k < j; ++k) {
                best = std::max(best,
                    TAB[i*n + k] + TAB[(k + 1)*n + j]);
            }

            TAB[i*n + j] = best;
        }
    }
}
