#include <vector>
#include <cmath>
#include <omp.h>

void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev)
{
    constexpr double eps = 0.1;
    const double invSqrtN = 1.0 / std::sqrt(static_cast<double>(n));

    /* ---------- 1. Compute mean ---------- */
    #pragma omp parallel for
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        for (int i = 0; i < n; ++i) s += data[i][j];
        mean[j] = s / n;
    }

    /* ---------- 2. Compute std‑dev and normalise data ---------- */
    #pragma omp parallel for
    for (int j = 0; j < m; ++j) {
        double ss = 0.0;
        for (int i = 0; i < n; ++i) {
            const double v = data[i][j] - mean[j];
            ss += v * v;
        }
        double sdev = std::sqrt(ss / n);
        if (sdev <= eps) sdev = 1.0;          // avoid division by zero
        stddev[j] = sdev;

        const double scale = invSqrtN / sdev; // 1 / (sqrt(n) * stddev)
        for (int i = 0; i < n; ++i) {
            data[i][j] = (data[i][j] - mean[j]) * scale;
        }
    }

    /* ---------- 3. Compute correlation matrix ---------- */
    #pragma omp parallel for
    for (int i = 0; i < m; ++i) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < m; ++j) {
            double c = 0.0;
            for (int k = 0; k < n; ++k) c += data[k][i] * data[k][j];
            corr[i][j] = c;
            corr[j][i] = c;
        }
    }
    corr[m-1][m-1] = 1.0;    // already set in loop, kept for clarity
}
