void kernel_jacobi_2d(int tsteps,
		      int n,
		      std::vector<std::vector<double>>& A,
		      std::vector<std::vector<double>>& B) {
    const double coeff = 0.2;

#pragma omp parallel
    {
        // Row pointers cache for inner loops
        std::vector<double*> Arow(n), Brow(n);
        for (int i = 0; i < n; ++i) {
            Arow[i] = A[i].data();
            Brow[i]  = B[i].data();
        }

