            /* 1st half of Jacobi sweep – update B from A  */
#pragma omp for collapse(2) schedule(static)
            for (int i = 1; i < n - 1; ++i) {
                double* Ai   = Arow[i];
                double* Ami1 = Arow[i-1];
                double* Ami2 = Arow[i+1];
                double* Bi   = Brow[i];
                for (int j = 1; j < n - 1; ++j) {
                    Bi[j] = coeff * (Ai[j] + Ai[j-1] + Ai[j+1] + Ami2[j] + Ami1[j]);
                }
            }

            /* 2nd half – update A from B  */
#pragma omp for collapse(2) schedule(static)
            for (int i = 1; i < n - 1; ++i) {
                double* Bi   = Brow[i];
                double* Bmi1 = Brow[i-1];
                double* Bmi2 = Brow[i+1];
                double* Ai   = Arow[i];
