/*
 * Optimized LU decomposition kernel.
 * The implementation keeps the exact semantics of the original routine
 * but rewrites the inner loops in a form that promotes compiler auto‑vectorisation
 * and reduces indexing overhead. A direct OpenMP parallelisation of the outermost
 * loop is **not** safe, because each row `i` depends on the results of previous
 * rows.  Therefore only the innermost loops are written in a straightforward,
 * easily vectorisable way.
 */
void kernel_lu(int n, std::vector<std::vector<double>>& A)
{
    // Work only with pointers to the underlying data of each row.
    std::vector<double*> rowPtr(n);
    for (int i = 0; i < n; ++i)
        rowPtr[i] = A[i].data();

    for (int i = 0; i < n; ++i) {
        // === Lower part: j < i ===
        double* A_i = rowPtr[i];
        for (int j = 0; j < i; ++j) {
            double sum = 0.0;
            double* A_kj = rowPtr[0] + j;           // reuse base pointer for column j
            for (int k = 0; k < j; ++k) {
                sum += A_i[k] * A_kj[k];
            }
            A_i[j] = (A_i[j] - sum) / rowPtr[j][j];
        }

        // === Upper part: j >= i ===
        for (int j = i; j < n; ++j) {
            double* A_ik = rowPtr[i];
            double* A_kj = rowPtr[0] + j;
            double sum = 0.0;
            for (int k = 0; k < i; ++k)
                sum += A_ik[k] * A_kj[k];
            A_i[j] -= sum;
        }
    }
