/* The arrays are passed as vectors of vectors in the harness.  To
   achieve better cache locality and parallelism we first re‑cast them
   as flattened 1‑D arrays while keeping the original interface. */

static inline double* flatten(const std::vector<std::vector<double>>& mat)
{
    return (double*)mat.data();           // rows are contiguous in C++
}

void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q)
{
    // Helper pointers to the underlying data
    double* A_flat = flatten(A);
    double* R_flat = flatten(R);
    double* Q_flat = flatten(Q);

    // Row-major: element (i,j) is at index i*n + j
    #pragma omp parallel for schedule(static)
    for (int k = 0; k < n; ++k) {
        // ===== 1. Compute R[k][k] = ||A[:,k]||
        double nrm = 0.0;
        for (int i = 0; i < m; ++i) {
            double v = A_flat[i*n + k];
            nrm += v*v;
        }
        double rkk = std::sqrt(nrm);
        R_flat[k*n + k] = rkk;

        // ===== 2. Compute Q[:,k] = A[:,k] / R[k][k]
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i) {
            Q_flat[i*n + k] = A_flat[i*n + k] / rkk;
        }

        // ===== 3. Orthogonalise remaining columns
        for (int j = k + 1; j < n; ++j) {
            // Compute R[k][j] = Q[:,k]^T * A[:,j]
            double rkj = 0.0;
            for (int i = 0; i < m; ++i) {
                rkj += Q_flat[i*n + k] * A_flat[i*n + j];
            }
            R_flat[k*n + j] = rkj;

            // Update A[:,j] -= Q[:,k] * R[k][j]
            #pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i) {
                A_flat[i*n + j] -= Q_flat[i*n + k] * rkj;
            }
        }
    }
}
