void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y) {

    /* LU-factorisation : A = L*U  with unit diagonal in L */
    for (int i = 0; i < n; ++i) {
        /* --- 1. fill sub‑diagonal of row i  --- */
        for (int j = 0; j < i; ++j) {
            double w = A[i][j];
            const std::vector<double>& Ai = A[i];
            const std::vector<double>& Aj = A[j];
            for (int k = 0; k < j; ++k) {
                w -= Ai[k] * Aj[k];
            }
            A[i][j] = w / Aj[j];
        }

        /* --- 2. fill super‑diagonal of row i  --- */
        for (int j = i; j < n; ++j) {
            double w = A[i][j];
            for (int k = 0; k < i; ++k) {
                w -= A[i][k] * A[k][j];
            }
            A[i][j] = w;                      // U part (diagonal on i==j)
        }
    }

    /* Forward substitution: L*y = b   (L has unit diagonal) */
    for (int i = 0; i < n; ++i) {
        double w = b[i];
        for (int j = 0; j < i; ++j) {
            w -= A[i][j] * y[j];
        }
        y[i] = w;                           // y[i] = w
    }

    /* Backward substitution: U*x = y */
    for (int i = n - 1; i >= 0; --i) {
        double w = y[i];
        for (int j = i + 1; j < n; ++j) {
            w -= A[i][j] * x[j];
        }
        x[i] = w / A[i][i];
    }
}
