    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < m; ++j) Aptr[i * m + j] = A[i][j];
    }
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) Bptr[i * n + j] = B[i][j];
    }
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) Cptr[i * n + j] = C[i][j];
    }

    // Main kernel: parallel over rows
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        double* Ai = Aptr + i * m;        // row i of A
        double* Bi = Bptr + i * n;        // row i of B
        double bii = Ai[i];               // A[i][i]
        for (int j = 0; j < n; ++j) {
            double temp2 = 0.0;
            double* Cij = Cptr + i * n + j;   // &C[i][j]
            double* CijRow = Cptr + j;        // column j of C
            double* Bj = Bptr + j;            // column j of B

            // Accumulate low‑triangular part
            for (int k = 0; k < i; ++k) {
                double aik = Ai[k];
                double bk = Bj[k * n + j];     // B[k][j]
                CijRow[k * n + j] += alpha * B[i][j] * aik;
                temp2 += bk * aik;
