/* Based on a Fortran code fragment from Figure 5 of
 * "Automatic Data and Computation Decomposition on Distributed Memory Parallel Computers"
 * by Peizong Lee and Zvi Meir Kedem, TOPLAS, 2002
 */
void kernel_adi(int tsteps, int n,
		std::vector<std::vector<double>>& u,
		std::vector<std::vector<double>>& v,
		std::vector<std::vector<double>>& p,
		std::vector<std::vector<double>>& q) {
    const double DX = 1.0 / n;
    const double DY = 1.0 / n;
    const double DT = 1.0 / tsteps;
    const double B1 = 2.0;
    const double B2 = 1.0;
    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);
    const double a   = -mul1 / 2.0;
    const double b   = 1.0 + mul1;
    const double c   = a;
    const double d   = -mul2 / 2.0;
    const double e   = 1.0 + mul2;
    const double f   = d;

    /* The outer time loop must remain sequential – the algorithm is
       inherently "time‑marching".  The inner spatial loops are
       completely independent, so we parallelise them with OpenMP.
    */
    for (int t = 1; t <= tsteps; ++t) {
        /* ---------------------------------------------------------------- */
        /* 1st phase: update column‑wise (index i)                            */
        /* ---------------------------------------------------------------- */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            /* Set boundary values for this column */
            v[0][i] = 1.0;
            p[i][0] = 0.0;
            q[i][0] = v[0][i];

            /* Forward sweep along j */
            for (int j = 1; j < n - 1; ++j) {
                const double denom = a * p[i][j - 1] + b;
                p[i][j] = -c / denom;
                q[i][j] = (-d * u[j][i - 1] + (1.0 + 2.0 * d) * u[j][i] -
                           f * u[j][i + 1] - a * q[i][j - 1]) / denom;
            }

            v[n - 1][i] = 1.0;

            /* Backward sweep along j */
            for (int j = n - 2; j >= 1; --j)
                v[j][i] = p[i][j] * v[j + 1][i] + q[i][j];
        }

        /* ---------------------------------------------------------------- */
        /* 2nd phase: update row‑wise (index i)                               */
        /* ---------------------------------------------------------------- */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            /* Set boundary values for this row */
            u[i][0] = 1.0;
            p[i][0] = 0.0;
            q[i][0] = u[i][0];

            /* Forward sweep along j */
            for (int j = 1; j < n - 1; ++j) {
                const double denom = d * p[i][j - 1] + e;
                p[i][j] = -f / denom;
                q[i][j] = (-a * v[i - 1][j] + (1.0 + 2.0 * a) * v[i][j] -
                           c * v[i + 1][j] - d * q[i][j - 1]) / denom;
            }

            u[i][n - 1] = 1.0;

            /* Backward sweep along j */
            for (int j = n - 2; j >= 1; --j)
                u[i][j] = p[i][j] * u[i][j + 1] + q[i][j];
        }
    }
}
