/* Optimised 2‑D FDTD kernel.
   The interface is unchanged; only the body has been rewritten to
   (1) minimise cache misses by using flat arrays
   (2) parallelise the for‑loops with OpenMP
   (3) use simple arithmetic on double pointers for speed. */
void kernel_fdtd_2d(int tmax,
                    int nx,
                    int ny,
                    std::vector<std::vector<double>>& ex,
                    std::vector<std::vector<double>>& ey,
                    std::vector<std::vector<double>>& hz,
                    std::vector<double>& _fict_)   {
    const std::size_t NYX = static_cast<std::size_t>(nx)*ny;
    /* Create contiguous buffers that mirror the 2‑D layout of ex, ey, hz. */
    std::vector<double> exf(NYX), eyf(NYX), hzf(NYX);

    /* Copy initial values into the flat buffers. */
    for (int i = 0; i < nx; ++i)
        std::memcpy(&exf[i*ny], ex[i].data(), ny*sizeof(double));
    for (int i = 0; i < nx; ++i)
        std::memcpy(&eyf[i*ny], ey[i].data(), ny*sizeof(double));
    for (int i = 0; i < nx; ++i)
        std::memcpy(&hzf[i*ny], hz[i].data(), ny*sizeof(double));

    for (int t = 0; t < tmax; ++t) {
        /* 1. Update ey[0][j] with the fictitious source. */
        double src = _fict_[t];
        double *ey0 = &eyf[0];
        #pragma omp parallel for schedule(static)
        for (int j = 0; j < ny; ++j)
            ey0[j] = src;

        /* 2. Update ey[i][j] for i>0. */
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < nx; ++i) {
            double *ey_ip = &eyf[i*ny];
            double *hz_ip  = &hzf[i*ny];
            double *hz_im = &hzf[(i-1)*ny];
            for (int j = 0; j < ny; ++j)
                ey_ip[j] -= 0.5*(hz_ip[j] - hz_im[j]);
        }

        /* 3. Update ex[i][j] for j>0. */
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 0; i < nx; ++i) {
            double *ex_ip  = &exf[i*ny];
            double *hz_ip  = &hzf[i*ny];
            double *hz_im1 = (j>0? &hzf[i*ny-1] : nullptr);
            for (int j = 1; j < ny; ++j)
                ex_ip[j] -= 0.5*(hz_ip[j] - hz_ip[j-1]);
        }

        /* 4. Update hz[i][j] for i<nx-1 and j<ny-1. */
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 0; i < nx-1; ++i) {
            double *hz_ip  = &hzf[i*ny];
            double *ex_ip  = &exf[i*ny];
            double *ex_ip1 = &exf[(i+1)*ny];
            double *ey_ip  = &eyf[i*ny];
            double *ey_ip1 = &eyf[(i+1)*ny];
            for (int j = 0; j < ny-1; ++j)
                hz_ip[j] -= 0.7*(ex_ip[j+1] - ex_ip[j] + ey_ip1[j] - ey_ip[j]);
        }
    }

    /* Copy results back to the original 2‑D structures. */
    for (int i = 0; i < nx; ++i)
        std::memcpy(ex[i].data(), &exf[i*ny], ny*sizeof(double));
    for (int i = 0; i < nx; ++i)
        std::memcpy(ey[i].data(), &eyf[i*ny], ny*sizeof(double));
    for (int i = 0; i < nx; ++i)
        std::memcpy(hz[i].data(), &hzf[i*ny], ny*sizeof(double));
